export function PerformanceClient() {
  const [compareMode, setCompareMode] = useState(false);
  const [selected, setSelected] = useState<string[]>([]);
  const [drawerCabinet, setDrawerCabinet] = useState<string | null>(null);
  const [compareOpen, setCompareOpen] = useState(false);

  function toggleCompare() {
    if (compareMode) {
      setCompareMode(false);
      setSelected([]);
    } else {
      setCompareMode(true);
    }
  }

  function toggleSelect(name: string, checked: boolean) {
    setSelected((prev) => {
      if (checked) {
        if (prev.length >= 2) return prev;
        return [...prev, name];
      }
      return prev.filter((n) => n !== name);
    });
  }

  function openDetail(name: string) {
    if (!compareMode) setDrawerCabinet(name);
  }

  const selectedStatus = `${selected.length} / 2 cabinets sélectionnés`;
  const compareTitle = selected.length === 2 ? `${selected[0]} vs ${selected[1]}` : "";

  return (
    <>
      <div className="hero">
        <div>
          <div className="hero-eyebrow">Tableau de bord · pilotage des cabinets licenciés</div>
          <h1 className="hero-title">Performance des <strong>ingénieurs</strong> au sein du cabinet</h1>
          <p className="hero-sub">Suivi consolidé des 5 ingénieurs du cabinet ASTRAEOS · trajectoire 2026 (année en cours) en mini-graphique · cliquez sur une ligne pour voir la comparaison 2024 / 2025 / 2026 · activez &quot;Comparer&quot; pour confronter 2 cabinets côte à côte.</p>
        </div>
        <div className="hero-actions">
          <button className="btn btn-gold btn-sm">Exporter</button>
        </div>
      </div>

      <div className="kpis kpis-4 mb-20">
        <div className="kpi"><div className="kpi-label">CA cumul réseau</div><div className="kpi-value">2 384 600 <span className="unit">€</span></div><div className="kpi-meta">cumul depuis janvier 2026</div></div>
        <div className="kpi"><div className="kpi-label">Croissance moyenne</div><div className="kpi-value gold">+18,4 <span className="unit">%</span></div><div className="kpi-meta">vs même période 2025</div></div>
        <div className="kpi"><div className="kpi-label">Cabinets en croissance</div><div className="kpi-value">26 <span className="unit">/30</span></div><div className="kpi-meta">+5 % minimum vs 2025</div></div>
        <div className="kpi"><div className="kpi-label">Cabinets en alerte</div><div className="kpi-value" style={{ color: "var(--orange-text)" }}>3</div><div className="kpi-meta">décroissance &gt; 10 %</div></div>
      </div>

      <div className="card mb-24">
        <div className="card-header">
          <div className="card-title"><svg><use href="#i-business" /></svg>Performance par ingénieur · trajectoire mensuelle 2026</div>
          <div style={{ display: "flex", alignItems: "center", gap: "10px" }}>
            {compareMode && (
              <span style={{ fontSize: "11px", color: "var(--navy-300)", fontStyle: "italic" }}>{selectedStatus}</span>
            )}
            <button
              className={compareMode ? "btn btn-gold btn-sm" : "btn btn-ghost btn-sm"}
              onClick={toggleCompare}
              style={{ display: "inline-flex", alignItems: "center", gap: "6px" }}
            >
              {compareMode ? (
                <svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" strokeWidth="2.2"><path d="M6 18 L 18 6 M 6 6 L 18 18" /></svg>
              ) : (
                <svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" strokeWidth="1.8"><path d="M9 4 L 9 20 M 15 4 L 15 20 M 4 9 L 20 9 M 4 15 L 20 15" /></svg>
              )}
              {compareMode ? "Annuler" : "Comparer"}
            </button>
            {selected.length === 2 && (
              <button className="btn btn-gold btn-sm" onClick={() => setCompareOpen(true)}>Voir comparaison →</button>
            )}
          </div>
        </div>
        <table className="dt" style={{ fontSize: "12.5px" }}>
          <thead>
            <tr>
              {compareMode && <th style={{ width: "32px" }}></th>}
              <th style={{ width: "30%" }}>Cabinet</th>
              <th className="num" style={{ width: "13%" }}>CA 2026<br /><span style={{ fontWeight: 400, color: "var(--navy-300)", fontSize: "10.5px" }}>cumul depuis janvier</span></th>
              <th className="num" style={{ width: "12%" }}>CA 2025<br /><span style={{ fontWeight: 400, color: "var(--navy-300)", fontSize: "10.5px" }}>même période</span></th>
              <th className="num" style={{ width: "10%" }}>Variation</th>
              <th style={{ width: "35%" }}>
                <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                  <span>Trajectoire 12 mois · <span style={{ color: "var(--gold-deep)", fontWeight: 700 }}>année en cours</span></span>
                  <span style={{ fontSize: "10px", color: "var(--navy-300)", fontWeight: 500, fontStyle: "italic" }}>survolez pour voir les chiffres</span>
                </div>
              </th>
            </tr>
          </thead>
          <tbody>
            {ROWS.map((r, i) => {
              const isChecked = selected.includes(r.name);
              const disabled = compareMode && !isChecked && selected.length >= 2;
              return (
                <tr key={i} className="perf-row" data-cabinet={r.name}>
                  {compareMode && (
                    <td style={{ width: "32px" }}>
                      <input
                        type="checkbox"
                        checked={isChecked}
                        disabled={disabled}
                        onChange={(e) => toggleSelect(r.name, e.target.checked)}
                        onClick={(e) => e.stopPropagation()}
                        style={{ width: "14px", height: "14px", cursor: "pointer", accentColor: "var(--gold)" }}
                      />
                    </td>
                  )}
                  <td onClick={() => openDetail(r.name)} style={{ cursor: "pointer" }}>
                    <div style={{ display: "flex", alignItems: "center", gap: "9px" }}>
                      <div className={`tlogo tlogo-sm ${r.logoClass}`}>{r.initials}</div>
                      <div>
                        <div className="cell-primary" style={{ fontSize: "12.5px" }}>{r.name}</div>
                        <div style={{ fontSize: "10.5px", color: "var(--navy-300)" }}>{r.office} · {r.manager}</div>
                      </div>
                    </div>
                  </td>
                  <td className="num cell-money gold" style={{ fontWeight: 700 }}>{r.ca2026}</td>
                  <td className="num cell-money" style={{ color: "var(--navy-300)" }}>{r.ca2025}</td>
                  <td className="num"><span style={{ color: r.variationUp ? "var(--green-text)" : "var(--orange-text)", fontWeight: 700 }}>{r.variation}</span></td>
                  <td style={{ padding: "8px 10px" }} dangerouslySetInnerHTML={{ __html: r.spark }} />
                </tr>
              );
            })}
            <tr style={{ background: "var(--ivory)" }}>
              <td colSpan={compareMode ? 6 : 5} style={{ textAlign: "center", fontSize: "11.5px", color: "var(--navy-300)", padding: "14px" }}>… 25 autres cabinets · <a style={{ color: "var(--gold)", fontWeight: 700, cursor: "pointer" }}>Voir tous les 4 ingénieurs</a></td>
            </tr>
            <tr style={{ background: "var(--gold-200)", fontWeight: 700 }}>
              {compareMode && <td></td>}
              <td><strong>Total réseau (5 personnes)</strong></td>
              <td className="num cell-money">2 384 600 €</td>
              <td className="num cell-money" style={{ color: "var(--medium-400)" }}>1 937 000 €</td>
              <td className="num"><span style={{ color: "var(--green-text)", fontWeight: 700 }}>▲ 23,1 %</span></td>
              <td style={{ fontSize: "10.5px", color: "var(--navy-300)", fontStyle: "italic" }}>moyenne pondérée du cabinet</td>
            </tr>
          </tbody>
        </table>
      </div>

      <DetailDrawer open={drawerCabinet !== null} name={drawerCabinet ?? ""} onClose={() => setDrawerCabinet(null)} />
      <CompareDrawer open={compareOpen} title={compareTitle} onClose={() => setCompareOpen(false)} />
    </>
  );
}

